import{_ as a,o as e,c as o,ai as i}from"./chunks/framework.DKRJm8HN.js";const d=JSON.parse('{"title":"关于 AI 的思考","description":"","frontmatter":{"title":"关于 AI 的思考","date":"2020-07-02"},"headers":[],"relativePath":"docs/C-Thoughts/thoughts-on-ai.md","filePath":"docs/C-Thoughts/thoughts-on-ai.md"}'),s={name:"docs/C-Thoughts/thoughts-on-ai.md"};function r(n,t,l,h,p,_){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="关于-ai-的思考" tabindex="-1">关于 AI 的思考 <a class="header-anchor" href="#关于-ai-的思考" aria-label="Permalink to “关于 AI 的思考”">​</a></h1><p>最近在思考人工智能对我们工作方式的影响。</p><p>AI 工具确实在改变很多事情。写代码、写文档、分析数据，这些任务的效率都提高了不少。但我也发现一个问题：过度依赖 AI 会让自己的思考能力退化。</p><p>我现在的做法是：</p><ul><li>用 AI 处理重复性工作</li><li>核心决策和创意工作还是自己来</li><li>把 AI 当作助手，而不是替代品</li></ul><p>技术应该是增强人类能力的工具，而不是让我们变懒的借口。</p><p>保持独立思考的能力，这可能是 AI 时代最重要的事情。</p>',7)])])}const u=a(s,[["render",r]]);export{d as __pageData,u as default};
